import React, { useState } from "react";
import { ArrowDownLeft } from "lucide-react";

export default function SavingsWithdrawScreen({ savingsBalance, onWithdraw, goBack }) {
  const [amount, setAmount] = useState("");

  const handleWithdraw = () => {
    if (!amount || isNaN(amount) || Number(amount) <= 0) {
      alert("Enter a valid amount");
      return;
    }
    if (Number(amount) > savingsBalance) {
      alert("Insufficient savings balance");
      return;
    }
    onWithdraw(Number(amount));
    setAmount("");
  };

  return (
    <div className="px-6 pb-24 bg-gray-50 min-h-screen animate-fade-in">
      <button
        onClick={goBack}
        className="mb-6 text-teal-600 font-medium flex items-center gap-2"
      >
        ← Back
      </button>

      <h1 className="text-2xl font-bold mb-6 text-gray-800">Withdraw from Savings</h1>

      <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-md space-y-4">
        <p className="text-gray-500 font-medium">Current savings: ${savingsBalance}</p>
        <input
          type="number"
          placeholder="Enter amount"
          value={amount}
          onChange={(e) => setAmount(e.target.value)}
          className="w-full border border-gray-200 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-red-500"
        />
        <button
          onClick={handleWithdraw}
          className="w-full flex items-center justify-center gap-2 py-3 bg-gradient-to-r from-red-600 to-red-700 text-white rounded-xl hover:opacity-90 transition-opacity"
        >
          <ArrowDownLeft className="w-5 h-5" /> Withdraw
        </button>
      </div>
    </div>
  );
}
